#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, N, sizeof(int), compare);
        int moves = 0;
        int j = 1;
        for (int i = 0; i < N; i++) {
            if (arr[i] != j) {
                moves++;
            } else {
                j++;
            }
        }
        printf("%d\n", moves);
    }
    return 0;
}

