const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextLine() {
    return lines[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextIntArray() {
    return nextLine().split(' ').map(Number);
}

let T = nextInt();
while (T-- > 0) {
    let N = nextInt();
    let arr = nextIntArray();
    arr.sort((a, b) => a - b);
    let moves = 0;
    let j = 1;
    for (let i = 0; i < N; i++) {
        if (arr[i] !== j) {
            moves++;
        } else {
            j++;
        }
    }
    console.log(moves);
}
